const {
    Document, Packer, Paragraph, TextRun, HeadingLevel,
    AlignmentType, LevelFormat, BorderStyle, PageNumber,
    Header, Footer
} = require('docx');
const fs = require('fs');

// 200 ISTQB CTFL v4.0 questions grouped by chapter
// Format: { q, opts:[a,b,c,d], ans:'a'|'b'|'c'|'d', lo:'FL-x.x.x', rationale }

const questions = [part1,part2]

const part1 = [
{ ch:1, lo:"FL-1.1.1", q:"Which of the following statements describe a valid test objective?", opts:["a) To prove that there are no unfixed defects in the system under test","b) To prove that there will be no failures after the implementation of the system into production","c) To reduce the risk level of the test object and to build confidence in the quality level","d) To verify that there are no untested combinations of inputs"], ans:"c", rationale:"Testing cannot prove absence of defects. A key objective is reducing risk and building confidence in quality." },
{ ch:1, lo:"FL-1.1.2", q:"A developer fixes a defect and hands the build back to the tester. The tester re-runs the test case that originally found the defect. This is an example of:", opts:["a) Regression testing","b) Confirmation testing","c) Exploratory testing","d) Component testing"], ans:"b", rationale:"Confirmation testing (re-testing) verifies that a specific defect has been fixed." },
{ ch:1, lo:"FL-1.3.1", q:"Which of the following is the BEST example of the 'absence-of-errors fallacy' testing principle?", opts:["a) A system passes all tests but fails to meet user needs","b) A system has no defects in the login module but has many in payment","c) A team finds no bugs in the final sprint","d) A tester cannot find any more defects after extensive testing"], ans:"a", rationale:"Finding and fixing defects is useless if the system doesn't meet user needs — the absence-of-errors fallacy." },
{ ch:1, lo:"FL-1.3.1", q:"The principle 'defects cluster together' implies that:", opts:["a) All modules have an equal probability of containing defects","b) Testing effort should be evenly spread across all modules","c) A small number of modules contain the majority of defects","d) Defects found together are always related"], ans:"c", rationale:"Defect clustering (Pareto principle) shows that most defects are concentrated in a few modules." },
{ ch:1, lo:"FL-1.3.1", q:"Which of the following is NOT one of the seven testing principles?", opts:["a) Early testing saves time and money","b) Testing is context dependent","c) Testing proves software correctness","d) Exhaustive testing is impossible"], ans:"c", rationale:"Testing can never prove correctness — it can only find defects. This is NOT a valid testing principle." },
{ ch:1, lo:"FL-1.4.1", q:"Which test activity involves identifying testable features and defining test conditions?", opts:["a) Test implementation","b) Test execution","c) Test analysis","d) Test completion"], ans:"c", rationale:"Test analysis includes analyzing the test basis and identifying testable features and test conditions." },
{ ch:1, lo:"FL-1.2.3", q:"What is the MAIN difference between an error, a defect, and a failure?", opts:["a) They are synonyms used interchangeably in testing","b) An error is a human mistake, a defect is its manifestation in the product, a failure occurs when the defect executes","c) A failure is found during static testing, a defect during dynamic testing","d) An error is found in code, a defect in requirements, a failure in production"], ans:"b", rationale:"An error (mistake) by a human causes a defect (fault) in the code; when executed under certain conditions, a defect causes a failure." },
{ ch:1, lo:"FL-1.3.1", q:"Which of the following is a consequence of the 'tests wear out' principle?", opts:["a) Test cases should be deleted after each release","b) The same tests should be run repeatedly for maximum effectiveness","c) Test cases need to be reviewed and updated to remain effective","d) Automated tests should be avoided as they wear out faster"], ans:"c", rationale:"Running the same tests repeatedly finds fewer new defects over time; tests must be updated to remain effective." },
{ ch:1, lo:"FL-1.3.1", q:"A team is building a life-critical medical device. How does the testing principle 'testing is context dependent' apply?", opts:["a) Less testing is needed since medical devices are well regulated","b) More rigorous testing with formal methods is appropriate given the high risk","c) Context has no impact; all testing should follow the same approach","d) Only black-box testing is suitable for medical devices"], ans:"b", rationale:"Context (safety-critical domain) determines the rigor and formality of testing required." },
{ ch:1, lo:"FL-1.3.1", q:"Which of the following BEST explains why early testing saves time and money?", opts:["a) Defects found early are cheaper to fix than those found in later phases","b) Early testing means fewer test cases need to be written","c) Testers can skip system testing if unit testing was thorough","d) Early testing reduces the number of developers needed"], ans:"a", rationale:"The cost of fixing a defect increases exponentially the later it is found in the SDLC." },
{ ch:1, lo:"FL-1.4.1", q:"Which of the following activities is part of 'test planning'?", opts:["a) Writing test scripts for a specific feature","b) Determining entry and exit criteria","c) Executing test cases against the system","d) Identifying defects in source code"], ans:"b", rationale:"Test planning involves determining scope, approach, resources, schedules, and entry/exit criteria." },
{ ch:1, lo:"FL-1.2.3", q:"What does 'false positive' mean in the context of testing?", opts:["a) A test passes when it should have failed","b) A test is incorrectly classified as a high-priority test","c) A test incorrectly reports a defect that does not actually exist","d) A tester reports a defect that was already known"], ans:"c", rationale:"A false positive (false alarm) is when a test reports a failure but there is no actual defect." },
{ ch:1, lo:"FL-1.3.1", q:"A tester notices that running the same 50 regression tests every sprint no longer finds new defects. Which principle explains this?", opts:["a) Defects cluster together","b) Exhaustive testing is impossible","c) Tests wear out","d) Testing is context dependent"], ans:"c", rationale:"Tests wear out — the same tests become ineffective at finding new defects over repeated runs." },
{ ch:1, lo:"FL-1.2.3", q:"Which of the following is an example of a 'root cause' of a defect?", opts:["a) A NullPointerException thrown at runtime","b) An ambiguous requirement misinterpreted by the developer","c) A failing test case during system testing","d) A missing test condition in the test plan"], ans:"b", rationale:"Root cause is the fundamental reason for a defect — an ambiguous requirement misunderstood by the developer." },
{ ch:1, lo:"FL-1.2.1", q:"Which of the following BEST describes 'confirmation testing'?", opts:["a) Testing all features after each new release","b) Running tests to detect regressions in unchanged code","c) Re-executing a failed test after the defect has been fixed","d) Testing in a production-like environment"], ans:"c", rationale:"Confirmation testing verifies that a specific previously found defect has been corrected." },
{ ch:1, lo:"FL-1.4.1", q:"Test monitoring and control is BEST described as:", opts:["a) Writing test cases based on requirements","b) Continuously tracking test progress and taking corrective actions when needed","c) Setting up the test environment before test execution","d) Reviewing test results after all testing is complete"], ans:"b", rationale:"Test monitoring tracks test progress; test control takes corrective action when targets are not met." },
{ ch:1, lo:"FL-1.4.1", q:"Which of the following is an example of a test work product produced during test analysis?", opts:["a) Test script","b) Test conditions","c) Test execution report","d) Test summary report"], ans:"b", rationale:"Test analysis produces test conditions — the result of analyzing the test basis." },
{ ch:1, lo:"FL-1.3.1", q:"'Exhaustive testing is impossible' because:", opts:["a) Testers never have enough time","b) The number of input combinations and states is practically infinite","c) Requirements are always incomplete","d) Test environments never match production exactly"], ans:"b", rationale:"The combinatorial explosion of inputs, states, and sequences makes complete testing impractical." },
{ ch:1, lo:"FL-1.4.1", q:"Which testing activity does a tester perform when they analyze a failing test result and determine whether it represents an actual defect?", opts:["a) Test planning","b) Test analysis","c) Test completion","d) Test execution"], ans:"d", rationale:"During test execution, testers compare actual results to expected results and analyze discrepancies." },
{ ch:1, lo:"FL-1.1.1", q:"Which of the following is an objective of testing?", opts:["a) Proving that the software is defect-free","b) Providing information to stakeholders for decision making","c) Ensuring the development team writes better code","d) Replacing manual inspection with automated checks"], ans:"b", rationale:"A key testing objective is providing information to allow stakeholders to make informed decisions about quality." },
{ ch:1, lo:"FL-1.2.2", q:"Which of the following BEST describes the relationship between testing and quality assurance (QA)?", opts:["a) Testing and QA are the same thing","b) QA is a subset of testing focused on test execution","c) Testing is a form of quality control; QA focuses on process improvement","d) QA replaces testing in agile environments"], ans:"c", rationale:"Testing (quality control) is product-oriented, finding defects. QA is process-oriented, preventing defects." },
{ ch:1, lo:"FL-1.4.1", q:"A project uses formal exit criteria that must be met before testing can be considered complete. Which test activity sets these criteria?", opts:["a) Test execution","b) Test completion","c) Test planning","d) Test monitoring"], ans:"c", rationale:"Exit criteria are defined during test planning to determine when testing is sufficiently complete." },
{ ch:1, lo:"FL-1.2.3", q:"Which of the following is an example of a 'failure' as defined in software testing?", opts:["a) A developer writes incorrect logic in a function","b) A requirement contains an ambiguity","c) An application crashes when a user submits an empty form","d) A test case is missing an expected result"], ans:"c", rationale:"A failure is the observable incorrect behavior of the system — the application crashing is a failure." },
{ ch:1, lo:"FL-1.4.1", q:"A test basis includes all EXCEPT:", opts:["a) User stories","b) Architecture diagrams","c) The test execution log","d) Business process flows"], ans:"c", rationale:"The test execution log is a test work product, not a test basis. The test basis contains information used to design tests." },
{ ch:1, lo:"FL-1.5.2", q:"Which of the following BEST characterizes the 'shift left' approach to testing?", opts:["a) Moving testers to the development team permanently","b) Starting testing activities earlier in the SDLC","c) Replacing system testing with unit testing","d) Automating all test execution"], ans:"b", rationale:"Shift left means moving testing activities earlier (to the left on the timeline) to find defects sooner." },
{ ch:1, lo:"FL-1.1.1", q:"In the context of software testing, what is a 'test oracle'?", opts:["a) A tool that generates test cases automatically","b) A means of determining the expected outcome of a test","c) A database of previously found defects","d) A formal specification review technique"], ans:"b", rationale:"A test oracle is a source used to determine expected results — e.g., a specification, another system, or expert knowledge." },
{ ch:1, lo:"FL-1.5.1", q:"Which statement about the role of testing in DevOps is CORRECT?", opts:["a) Testing is performed only at the end of the pipeline","b) Testing is integrated throughout the CI/CD pipeline","c) Manual testing replaces automated testing in DevOps","d) Testers are not needed in DevOps teams"], ans:"b", rationale:"In DevOps, testing is continuous and embedded throughout the CI/CD pipeline — not just at the end." },
{ ch:1, lo:"FL-1.2.1", q:"Regression testing is PRIMARILY performed to:", opts:["a) Test new features added in the current release","b) Verify that changes have not adversely affected existing functionality","c) Find defects introduced during requirements analysis","d) Validate performance under expected loads"], ans:"b", rationale:"Regression testing checks that existing functionality is not broken by changes or new code." },
{ ch:1, lo:"FL-1.5.3", q:"Which of the following is a benefit of independent testing?", opts:["a) Testers always find more defects than developers","b) Independent testers can be less biased and may use a different perspective","c) It removes the need for code reviews","d) It reduces the overall project cost"], ans:"b", rationale:"Independent testers bring a different perspective and are not subject to confirmation bias of the author." },
{ ch:1, lo:"FL-1.4.1", q:"What is meant by 'test completion' in the test process?", opts:["a) When all test cases have been executed at least once","b) Archiving test assets and deriving lessons learned at the end of a test phase","c) When no more defects are found during testing","d) Closing all defect reports in the defect tracking system"], ans:"b", rationale:"Test completion involves collating data, archiving assets, and capturing lessons learned at end of a phase." },
{ ch:1, lo:"FL-1.2.3", q:"A defect was introduced into the code but no failure has been observed yet. Which condition is required for a failure to occur?", opts:["a) The defect must be in a safety-critical module","b) The defect must be executed under the right conditions","c) The defect must be in a section covered by a test case","d) The defect must be reported to the development team"], ans:"b", rationale:"A defect only causes a failure when it is executed and the conditions trigger the faulty behavior." },
{ ch:1, lo:"FL-1.1.1", q:"Which of the following BEST explains why testing contributes to higher quality software?", opts:["a) By preventing developers from writing any code with defects","b) By detecting defects early so they can be fixed before reaching the user","c) By ensuring 100% code coverage is achieved","d) By replacing the need for design reviews"], ans:"b", rationale:"Testing finds defects earlier in development, reducing the cost and impact of those defects on end users." },
{ ch:1, lo:"FL-1.2.3", q:"Which of the following is an example of a 'false negative' in testing?", opts:["a) A test fails but no real defect exists","b) A test passes even though an actual defect is present","c) A defect is found but marked as low priority incorrectly","d) A test case is designed with incorrect expected results"], ans:"b", rationale:"A false negative is when a test passes but an actual defect exists — the test failed to detect it." },
{ ch:1, lo:"FL-1.4.1", q:"Which of the following is the PRIMARY purpose of retrospectives in the testing process?", opts:["a) To formally close all open defects","b) To identify lessons learned and improve future processes","c) To get sign-off from stakeholders on test completion","d) To archive test cases for future use"], ans:"b", rationale:"Retrospectives capture lessons learned to improve quality and efficiency in future iterations or projects." },
{ ch:1, lo:"FL-1.2.1", q:"What distinguishes dynamic testing from static testing?", opts:["a) Static testing requires tools; dynamic testing does not","b) Dynamic testing executes the code; static testing does not","c) Static testing is done by testers; dynamic testing by developers","d) Dynamic testing is always automated; static testing is always manual"], ans:"b", rationale:"Dynamic testing runs the software to observe its behavior; static testing examines artifacts without executing code." },

// Chapter 2
{ ch:2, lo:"FL-2.1.1", q:"In which SDLC model does the rule 'for every development activity there is a corresponding test activity' apply?", opts:["a) Only in sequential models like Waterfall","b) Only in iterative models like Scrum","c) In all SDLC models","d) Only in incremental models"], ans:"c", rationale:"The principle that every development activity has a corresponding test activity applies in all SDLC models." },
{ ch:2, lo:"FL-2.2.1", q:"What is the PRIMARY difference between component testing and component integration testing?", opts:["a) Component testing uses stubs; integration testing does not","b) Component testing tests a single component in isolation; integration testing tests interactions between components","c) Component testing is performed by developers; integration testing by testers","d) Component testing is always automated; integration testing is always manual"], ans:"b", rationale:"Component testing isolates individual components; component integration testing examines their interactions." },
{ ch:2, lo:"FL-2.2.3", q:"Which test level is MOST concerned with verifying that the complete, integrated system meets specified requirements?", opts:["a) Component testing","b) Component integration testing","c) System testing","d) Acceptance testing"], ans:"c", rationale:"System testing verifies the behavior of the fully integrated system against specified requirements." },
{ ch:2, lo:"FL-2.2.4", q:"Which acceptance testing type involves the end users testing the system in a real or simulated production environment?", opts:["a) Alpha testing","b) Beta testing","c) Contract acceptance testing","d) Regulatory acceptance testing"], ans:"a", rationale:"Alpha testing is performed by end users (or representatives) at the developer's site before release." },
{ ch:2, lo:"FL-2.1.3", q:"In Test-Driven Development (TDD), tests are written:", opts:["a) After the code is written and reviewed","b) Before the code is written, to drive implementation","c) Only for regression testing purposes","d) Exclusively by QA engineers, not developers"], ans:"b", rationale:"In TDD, tests (unit tests) are written first, then the minimal code to pass them, then refactored." },
{ ch:2, lo:"FL-2.1.3", q:"Which of the following BEST describes Behavior-Driven Development (BDD)?", opts:["a) Tests are written based on code structure","b) Stakeholders collaborate using natural language (Given/When/Then) to specify behavior","c) Behavior testing replaces unit testing","d) BDD is only applicable to agile projects"], ans:"b", rationale:"BDD uses natural language scenarios (Given/When/Then) to describe expected behavior, fostering collaboration." },
{ ch:2, lo:"FL-2.3.1", q:"What is the MAIN purpose of a test environment?", opts:["a) To store test cases and test results","b) To provide a stable, controlled environment in which software can be tested","c) To automate test execution","d) To train new testers on the system"], ans:"b", rationale:"A test environment provides the infrastructure (hardware, software, data) needed to execute tests reliably." },
{ ch:2, lo:"FL-2.1.1", q:"In the V-model, component integration testing corresponds to which development phase?", opts:["a) System design","b) High-level design","c) Detailed design","d) Architecture design"], ans:"d", rationale:"In the V-model, component integration testing verifies the system/software architecture (integration level design)." },
{ ch:2, lo:"FL-2.3.2", q:"Which of the following is a NON-functional test type?", opts:["a) Boundary value analysis testing","b) Security testing","c) Decision table testing","d) Regression testing"], ans:"b", rationale:"Security testing is non-functional — it tests a quality characteristic (security), not specific functional behavior." },
{ ch:2, lo:"FL-2.2.4", q:"Beta testing differs from alpha testing in that beta testing is:", opts:["a) Performed by developers in a controlled environment","b) Done by end users in their own environment without the development team present","c) More structured and scripted than alpha testing","d) Only applicable to open-source software"], ans:"b", rationale:"Beta testing involves end users testing in their real environment, without developer oversight." },
{ ch:2, lo:"FL-2.1.2", q:"Which statement about testing in Agile/Scrum is CORRECT?", opts:["a) Testing is performed only at the end of each sprint","b) Testers are not part of the Scrum team","c) Testers collaborate throughout the sprint, including during planning and review","d) Regression testing is eliminated because of continuous integration"], ans:"c", rationale:"In Agile, testers participate throughout the sprint — in planning, development, daily standups, and review." },
{ ch:2, lo:"FL-2.1.3", q:"What is the MAIN purpose of acceptance test-driven development (ATDD)?", opts:["a) To ensure 100% code coverage","b) To create acceptance criteria before development to drive implementation","c) To replace system testing with acceptance testing","d) To document defects found during UAT"], ans:"b", rationale:"ATDD defines acceptance tests upfront, before development, to clarify requirements and drive implementation." },
{ ch:2, lo:"FL-2.2.2", q:"Which test level PRIMARILY focuses on defects in the interfaces and interactions between integrated components?", opts:["a) Component testing","b) Component integration testing","c) System testing","d) Acceptance testing"], ans:"b", rationale:"Component integration testing focuses on the interfaces and interactions between components." },
{ ch:2, lo:"FL-2.1.1", q:"In a sequential SDLC (Waterfall), which of the following is a major disadvantage from a testing perspective?", opts:["a) Too many test cases are created","b) Testing happens very late, making defect fixes expensive","c) Developers and testers cannot communicate effectively","d) Automation is impossible in sequential models"], ans:"b", rationale:"In Waterfall, testing occurs late in the lifecycle, making defects costly to fix." },
{ ch:2, lo:"FL-2.3.2", q:"Which of the following is a test type based on quality characteristics?", opts:["a) Smoke testing","b) Usability testing","c) Exploratory testing","d) Regression testing"], ans:"b", rationale:"Usability testing is a non-functional test type targeting the usability quality characteristic." },
{ ch:2, lo:"FL-2.1.5", q:"'Shift left' in the context of testing means:", opts:["a) Moving from manual to automated testing","b) Performing testing activities earlier in the development lifecycle","c) Reducing test coverage to save time","d) Shifting test execution to the left column of the Kanban board"], ans:"b", rationale:"Shift left advocates beginning testing activities earlier in the SDLC to find defects sooner and cheaper." },
{ ch:2, lo:"FL-2.4.1", q:"Which of the following is an example of maintenance testing?", opts:["a) Testing a new feature before its first release","b) Regression testing after a patch is applied to a production system","c) Testing individual components during development","d) Performing UAT before go-live"], ans:"b", rationale:"Maintenance testing is triggered by modifications (patches, enhancements) to an operational system." },
{ ch:2, lo:"FL-2.4.1", q:"Which of the following factors determines the scope of impact analysis for maintenance testing?", opts:["a) The number of test cases in the test suite","b) The degree of change and its potential impact on the rest of the system","c) The seniority of the test manager","d) The availability of automated testing tools"], ans:"b", rationale:"Impact analysis assesses what parts of the system are affected by a change to scope maintenance testing." },
{ ch:2, lo:"FL-2.1.4", q:"In the context of the test pyramid, which layer typically contains the MOST tests?", opts:["a) UI / End-to-end tests","b) API / Service tests","c) Unit / Component tests","d) Acceptance tests"], ans:"c", rationale:"The test pyramid has unit/component tests at the base — most numerous, fastest, and cheapest to run." },
{ ch:2, lo:"FL-2.2.4", q:"Which of the following BEST describes 'operational acceptance testing'?", opts:["a) Testing conducted by operations/sysadmin teams to verify the system is ready for operation","b) Testing performed by end users to validate business processes","c) Testing that verifies compliance with legal regulations","d) Testing done immediately before production deployment by developers"], ans:"a", rationale:"Operational acceptance testing verifies that operations staff can manage the system in production." },
{ ch:2, lo:"FL-2.2.4", q:"What type of test is MOST appropriate to verify that a software system meets contractual requirements?", opts:["a) System testing","b) Operational acceptance testing","c) Contract acceptance testing","d) Component testing"], ans:"c", rationale:"Contract acceptance testing verifies the system meets requirements specified in the contract." },
{ ch:2, lo:"FL-2.1.4", q:"Which of the following is TRUE about DevOps and testing?", opts:["a) DevOps eliminates the need for dedicated test environments","b) DevOps promotes automated testing integrated throughout the CI/CD pipeline","c) DevOps reduces the need for regression testing","d) DevOps requires all tests to be manual"], ans:"b", rationale:"DevOps integrates automated testing into the CI/CD pipeline for rapid, continuous feedback." },
{ ch:2, lo:"FL-2.1.1", q:"Which SDLC characteristic makes iterative models suitable for projects with evolving requirements?", opts:["a) All requirements are fixed at the start","b) Short cycles allow requirements to be refined and tested incrementally","c) Testing is deferred until all iterations are complete","d) Only non-functional requirements can change between iterations"], ans:"b", rationale:"Iterative models accommodate changing requirements by reviewing and testing in short, frequent cycles." },
{ ch:2, lo:"FL-2.1.1", q:"The test approach in a safety-critical project (e.g., aviation software) would MOST likely require:", opts:["a) Less formal testing due to extensive code reviews","b) Formal test methods, extensive documentation, and independent verification","c) Exploratory testing as the primary technique","d) Only automated testing to remove human error"], ans:"b", rationale:"Safety-critical contexts require high rigor: formal methods, extensive documentation, and independent V&V." },
{ ch:2, lo:"FL-2.1.3", q:"Which of the following is a characteristic of good unit tests in TDD?", opts:["a) They test multiple units together to find integration issues","b) They are fast, isolated, and independently repeatable","c) They require a complete environment setup","d) They are written after implementation to validate code"], ans:"b", rationale:"Good unit tests in TDD are fast, isolated (test one unit), and deterministic — they can run in any order." },
{ ch:2, lo:"FL-2.2.3", q:"System integration testing differs from component integration testing in that it focuses on:", opts:["a) Interactions between individual code modules","b) Interactions between systems, subsystems, or external services","c) Individual functions within a single component","d) End-user acceptance criteria"], ans:"b", rationale:"System integration testing verifies interactions between the system and external systems or services." },
{ ch:2, lo:"FL-2.4.1", q:"Which of the following describes 'smoke testing'?", opts:["a) Exhaustive testing of all critical paths in the system","b) A quick set of tests to check whether a build is stable enough for further testing","c) Testing performed in a production environment","d) Testing focused on performance under load"], ans:"b", rationale:"Smoke testing (build verification) checks that the most critical functions work before more detailed testing begins." },
{ ch:2, lo:"FL-2.1.2", q:"In Agile development, the 'definition of done' (DoD) PRIMARILY relates to:", opts:["a) When a user story is assigned to a developer","b) Agreed criteria that must be met for a story or feature to be considered complete, including testing","c) The list of tests that must be automated in a sprint","d) When a defect report is closed in the tracking system"], ans:"b", rationale:"The DoD is a shared agreement on what constitutes completeness, including passing tests." },
{ ch:2, lo:"FL-2.1.4", q:"Which of the following is a key benefit of test automation in a CI/CD pipeline?", opts:["a) It eliminates the need for manual exploratory testing","b) It provides fast feedback on code changes, reducing integration risk","c) It ensures 100% test coverage automatically","d) It replaces the need for a test plan"], ans:"b", rationale:"Automated tests in CI/CD pipelines give rapid feedback, catching regressions immediately after code changes." },
{ ch:2, lo:"FL-2.1.5", q:"Which of the following is a disadvantage of early test design (writing tests before code is available)?", opts:["a) Defects are found later in the SDLC","b) Test design may need significant rework if requirements change","c) There is no traceability between tests and requirements","d) It prevents the use of automated testing"], ans:"b", rationale:"Early test design risks rework if requirements evolve, since tests are tied to potentially unstable specs." },
{ ch:2, lo:"FL-2.2.1", q:"Regression testing is MOST valuable after:", opts:["a) Requirements gathering","b) Each significant code change, fix, or enhancement","c) The initial system architecture is defined","d) User acceptance testing is complete"], ans:"b", rationale:"Regression testing should be run after every code change to detect unintended impacts on existing behavior." },
{ ch:2, lo:"FL-2.4.1", q:"Which of the following BEST describes 'impact analysis' in maintenance testing?", opts:["a) Analyzing the impact of test failures on the project schedule","b) Identifying which parts of the system may be affected by a proposed change","c) Measuring the impact of testing effort on product quality","d) Assessing the risk of skipping test execution"], ans:"b", rationale:"Impact analysis identifies areas potentially affected by a change, helping scope maintenance testing." },
{ ch:2, lo:"FL-2.1.1", q:"In the V-model, system testing corresponds to which phase on the left side?", opts:["a) Unit design","b) Component design","c) System requirements","d) User requirements"], ans:"c", rationale:"In the V-model, system testing verifies the system requirements specification — the corresponding left-side phase." },

// Chapter 3
{ ch:3, lo:"FL-3.1.1", q:"Which of the following BEST describes the purpose of static testing?", opts:["a) To execute the software and observe its behavior under various conditions","b) To examine work products without executing the code to find defects","c) To measure software performance under load","d) To validate that the system meets user acceptance criteria"], ans:"b", rationale:"Static testing examines work products (requirements, design, code) without running the software." },
{ ch:3, lo:"FL-3.1.1", q:"Which of the following defects is BEST found using static testing rather than dynamic testing?", opts:["a) Performance bottlenecks under load","b) Ambiguous requirements that could be misinterpreted","c) Incorrect output for boundary values","d) Failure under simultaneous user connections"], ans:"b", rationale:"Ambiguous requirements are best caught in static reviews before they lead to misimplemented code." },
{ ch:3, lo:"FL-3.2.1", q:"Which of the following is a formal review type?", opts:["a) Walkthrough","b) Pair programming","c) Code inspection","d) Exploratory testing session"], ans:"c", rationale:"Inspection is the most formal review type with a defined process, roles, metrics, and exit criteria." },
{ ch:3, lo:"FL-3.2.1", q:"Which review type is MOST suitable when the author wants to receive informal feedback on a document from a few colleagues?", opts:["a) Inspection","b) Walkthrough","c) Informal review","d) Technical review"], ans:"c", rationale:"Informal reviews are lightweight, unstructured feedback sessions — appropriate for quick author-led reviews." },
{ ch:3, lo:"FL-3.2.3", q:"Which of the following is the PRIMARY role of a moderator in a formal review?", opts:["a) Writing the review report","b) Ensuring the review is conducted properly and mediating discussions","c) Providing the document to be reviewed","d) Creating the checklist used in the review"], ans:"b", rationale:"The moderator (facilitator) plans and runs the review meeting, ensuring it is effective and on track." },
{ ch:3, lo:"FL-3.2.2", q:"Which of the following is an activity performed in the 'individual review' phase of a formal review process?", opts:["a) Fixing defects found during the review","b) Each reviewer examines the document and notes potential defects and questions","c) The moderator creates a summary report","d) The author presents the document to the review team"], ans:"b", rationale:"Individual review (preparation) involves reviewers independently examining the document before the review meeting." },
{ ch:3, lo:"FL-3.2.2", q:"Which statement about checklists in reviews is CORRECT?", opts:["a) Checklists are only used in informal reviews","b) Checklists help reviewers focus on common defect types and ensure consistent coverage","c) A checklist replaces the need for a review meeting","d) Checklists are created by the author of the reviewed document"], ans:"b", rationale:"Checklists guide reviewers toward known defect-prone areas and promote consistency across reviewers." },
{ ch:3, lo:"FL-3.1.2", q:"Which of the following is a benefit of involving testers in requirement reviews?", opts:["a) Testers can eliminate the need for dynamic testing","b) Defects in requirements are found early before they are costly to fix","c) Testers can directly fix ambiguous requirements","d) It reduces the number of test cases needed"], ans:"b", rationale:"Reviewing requirements early allows testers to spot ambiguities, contradictions, and gaps before development." },
{ ch:3, lo:"FL-3.1.1", q:"Which of the following document types can be examined using static testing?", opts:["a) Only source code","b) Only test cases","c) Requirements, design documents, user stories, and source code","d) Only documents written in a formal specification language"], ans:"c", rationale:"Static testing applies to any work product: requirements, designs, user stories, test plans, and code." },
{ ch:3, lo:"FL-3.2.1", q:"What distinguishes a 'walkthrough' from an 'inspection'?", opts:["a) A walkthrough uses a checklist; an inspection does not","b) A walkthrough is led by the author; an inspection has a trained moderator and formal process","c) A walkthrough is more formal than an inspection","d) An inspection requires no preparation; a walkthrough requires preparation"], ans:"b", rationale:"Walkthroughs are author-led and informal; inspections are rigorous, moderator-led, with defined process and metrics." },
{ ch:3, lo:"FL-3.1.1", q:"Which of the following is an example of a defect typically found during a code review?", opts:["a) The application crashes when processing large files","b) An uninitialized variable that could cause unpredictable behavior","c) A security breach in the login module","d) Incorrect output when the network connection is slow"], ans:"b", rationale:"An uninitialized variable is a static code defect detectable without execution, perfect for code review." },
{ ch:3, lo:"FL-3.2.3", q:"In a formal review, which role is responsible for determining whether exit criteria are met?", opts:["a) Author","b) Reviewer","c) Moderator","d) Scribe"], ans:"c", rationale:"The moderator ensures the review process is followed, including confirming exit criteria are satisfied." },
{ ch:3, lo:"FL-3.2.4", q:"Which of the following is a success factor for formal reviews?", opts:["a) Using the review to evaluate the performance of the document author","b) Having clear objectives and defined entry and exit criteria","c) Conducting the review as quickly as possible to save project time","d) Limiting reviewers to the immediate development team only"], ans:"b", rationale:"Clear objectives and criteria ensure reviewers know what to look for and when the review is complete." },
{ ch:3, lo:"FL-3.2.2", q:"Which of the following is NOT a typical activity in a formal review process?", opts:["a) Planning the review","b) Individual preparation by reviewers","c) Executing test cases against the reviewed document","d) Fixing defects found during review"], ans:"c", rationale:"Executing test cases is a dynamic testing activity, not part of the static review process." },
{ ch:3, lo:"FL-3.2.1", q:"Which type of review is characterized by having the author present to answer questions while the review team examines the document?", opts:["a) Inspection","b) Walkthrough","c) Informal review","d) Technical review"], ans:"b", rationale:"In a walkthrough, the author guides the review team through the document and answers questions." },
{ ch:3, lo:"FL-3.2.1", q:"What is the PRIMARY purpose of a 'technical review'?", opts:["a) To assess whether a document meets legal compliance requirements","b) To evaluate a document from a technical perspective to find defects and gain consensus","c) To document all decisions made during the project","d) To provide informal feedback to the author"], ans:"b", rationale:"Technical reviews focus on technical soundness, finding defects, and building agreement among technical staff." },
{ ch:3, lo:"FL-3.2.2", q:"Which of the following is a metric that can be collected during a formal code inspection?", opts:["a) Response time under load","b) Number of defects found per page/hour","c) Number of test cases executed","d) Code coverage percentage"], ans:"b", rationale:"Defect density metrics (defects per page, inspection rate) are collected during formal inspections." },
{ ch:3, lo:"FL-3.1.1", q:"Which of the following BEST describes a 'defect' found during a review?", opts:["a) Any observation made by a reviewer, regardless of whether it is correct","b) A problem in the reviewed work product that needs to be fixed","c) An argument between the reviewer and the author","d) A test case that fails during execution"], ans:"b", rationale:"A defect found in a review is a problem in the work product that needs correction before it progresses." },
{ ch:3, lo:"FL-3.1.1", q:"Which of the following is TRUE about static analysis tools?", opts:["a) They execute the software to find runtime errors","b) They analyze source code without executing it to find issues like coding standard violations","c) They replace the need for any dynamic testing","d) They can only be applied to requirements documents"], ans:"b", rationale:"Static analysis tools scan code without executing it, flagging issues like unreachable code or standards violations." },
{ ch:3, lo:"FL-3.2.3", q:"Which of the following is a role in a formal review?", opts:["a) Developer","b) Scribe","c) Product owner","d) Release manager"], ans:"b", rationale:"The scribe (recorder) documents defects, decisions, and action items during the formal review meeting." },
{ ch:3, lo:"FL-3.2.2", q:"Why is it important to have entry criteria for a formal review?", opts:["a) To ensure the review is conducted as quickly as possible","b) To ensure the work product is in a suitable state before reviewers spend time on it","c) To limit the number of reviewers in the process","d) To ensure only the author reads the document before review"], ans:"b", rationale:"Entry criteria prevent waste by ensuring the document is complete and ready before reviewers invest time in it." },
{ ch:3, lo:"FL-3.2.1", q:"A review where a domain expert reads a document independently and provides written feedback is BEST classified as:", opts:["a) Inspection","b) Walkthrough","c) Informal review","d) Peer review"], ans:"c", rationale:"Independent, unstructured feedback without a formal process or meeting is an informal review." },

// Chapter 4
{ ch:4, lo:"FL-4.2.1", q:"Which black-box test technique divides input data into groups where all values in a group are expected to be processed the same way?", opts:["a) Boundary value analysis","b) Equivalence partitioning","c) Decision table testing","d) State transition testing"], ans:"b", rationale:"Equivalence partitioning divides inputs into classes where one representative value is sufficient per class." },
{ ch:4, lo:"FL-4.2.2", q:"Using 2-value boundary value analysis (BVA) on a field that accepts values from 10 to 20 (inclusive), which values would you test?", opts:["a) 9, 10, 15, 20, 21","b) 10, 20","c) 9, 10, 20, 21","d) 10, 11, 19, 20"], ans:"c", rationale:"2-value BVA tests the boundary value and its nearest neighbor outside: 9 (just below), 10 (min), 20 (max), 21 (just above)." },
{ ch:4, lo:"FL-4.2.3", q:"A decision table is MOST useful when:", opts:["a) The system behavior depends on a sequence of states","b) Complex combinations of conditions determine different actions","c) Input values need to be partitioned into equivalent classes","d) Testing the behavior at the boundary of input ranges"], ans:"b", rationale:"Decision tables are ideal for specifying and testing complex business rules involving combinations of conditions." },
{ ch:4, lo:"FL-4.2.4", q:"In state transition testing, a 'transition' represents:", opts:["a) A condition that triggers an event in the system","b) The movement from one system state to another in response to an event","c) An invalid state that should not be reached","d) A test case that covers multiple states"], ans:"b", rationale:"A transition is the change from one state to another, triggered by an event and possibly guarded by a condition." },
{ ch:4, lo:"FL-4.3.1", q:"Which of the following is an example of a white-box test technique?", opts:["a) Equivalence partitioning","b) Statement coverage","c) State transition testing","d) Use case testing"], ans:"b", rationale:"Statement coverage is a white-box technique based on the internal code structure." },
{ ch:4, lo:"FL-4.3.1", q:"What is the PRIMARY goal of 100% statement coverage?", opts:["a) Every decision in the code is evaluated to both true and false","b) Every executable statement in the code is executed at least once","c) All possible paths through the code are executed","d) All conditions in every decision are independently evaluated"], ans:"b", rationale:"Statement coverage ensures every executable statement is exercised at least once during testing." },
{ ch:4, lo:"FL-4.3.2", q:"Which coverage criterion is stronger: statement coverage or branch coverage?", opts:["a) Statement coverage, because it covers all lines of code","b) Branch coverage, because 100% branch coverage implies 100% statement coverage but not vice versa","c) They are equivalent","d) Statement coverage, because branches are a subset of statements"], ans:"b", rationale:"Branch coverage subsumes statement coverage — 100% branch coverage guarantees 100% statement coverage." },
{ ch:4, lo:"FL-4.2.4", q:"A login system has the following states: Logged Out, Logged In, Locked. A user who fails to log in 3 times moves to Locked. Which technique BEST tests this behavior?", opts:["a) Equivalence partitioning","b) Boundary value analysis","c) State transition testing","d) Decision table testing"], ans:"c", rationale:"State transition testing models and tests systems that behave differently based on current state and events." },
{ ch:4, lo:"FL-4.2.1", q:"Using equivalence partitioning on a field that accepts ages 18-65, which partitions are correct?", opts:["a) Invalid: <18; Valid: 18-65; Invalid: >65","b) Invalid: <0; Valid: 0-65; Invalid: >65","c) Valid: 18-65; Invalid: all others are one partition","d) Invalid: <18, >65; Valid: 18-65 split into sub-partitions"], ans:"a", rationale:"EP creates at least one valid partition (18-65) and two invalid partitions (<18 and >65)." },
{ ch:4, lo:"FL-4.3.2", q:"Which of the following BEST describes 'branch coverage'?", opts:["a) Every line of code is executed","b) Every possible output value is tested","c) Every branch (true/false outcome) of each decision point is exercised","d) All possible combinations of conditions are tested"], ans:"c", rationale:"Branch coverage requires that each decision outcome (true and false branch) is exercised at least once." },
{ ch:4, lo:"FL-4.4.1", q:"A test charter in exploratory testing TYPICALLY defines:", opts:["a) The exact test cases to be executed in a session","b) The mission, scope, and time-box of the exploratory testing session","c) The expected results for each test","d) The number of defects expected to be found"], ans:"b", rationale:"A charter guides exploratory testing by defining the mission (what to explore), scope, and session time-box." },
{ ch:4, lo:"FL-4.4.1", q:"Which of the following is NOT a characteristic of exploratory testing?", opts:["a) Tests are designed and executed simultaneously","b) Testers use learning and creativity to discover defects","c) All test cases are pre-specified before the session begins","d) Sessions are time-boxed and guided by a test charter"], ans:"c", rationale:"Pre-specified tests are scripted testing. Exploratory testing designs and executes tests simultaneously." },
{ ch:4, lo:"FL-4.2.2", q:"3-value BVA on a range of 1-10 (inclusive) would test which values?", opts:["a) 1, 10","b) 0, 1, 10, 11","c) 0, 1, 2, 9, 10, 11","d) 1, 5, 10"], ans:"c", rationale:"3-value BVA tests each boundary plus its immediate neighbors: 0 (below min), 1, 2 (above min), 9 (below max), 10, 11 (above max)." },
{ ch:4, lo:"FL-4.2.3", q:"Which test design technique is MOST appropriate for testing a system that processes multiple independent conditions and their effect on system output?", opts:["a) State transition testing","b) Decision table testing","c) Boundary value analysis","d) Use case testing"], ans:"b", rationale:"Decision tables handle multiple conditions and their combined effects on outputs systematically." },
{ ch:4, lo:"FL-4.3.1", q:"What does 'test coverage' measure in white-box testing?", opts:["a) The percentage of requirements covered by test cases","b) The degree to which code structures have been exercised by tests","c) The number of defects found relative to the test effort","d) The ratio of passed to failed test cases"], ans:"b", rationale:"White-box coverage measures how much of the code structure (statements, branches, paths) has been exercised." },
{ ch:4, lo:"FL-4.2.5", q:"Use case testing derives tests from:", opts:["a) The internal code structure of the system","b) Interactions between actors and the system to achieve specific goals","c) Boundary values of input fields","d) Combinations of condition values in a decision table"], ans:"b", rationale:"Use case testing derives scenarios from use cases — actor-system interactions to accomplish a goal." },
{ ch:4, lo:"FL-4.4.1", q:"Which of the following is a test technique based on experience?", opts:["a) Boundary value analysis","b) Statement coverage","c) Error guessing","d) Equivalence partitioning"], ans:"c", rationale:"Error guessing relies on tester experience and intuition to identify likely defects, not formal derivation." },
{ ch:4, lo:"FL-4.1.1", q:"Which of the following CORRECTLY describes a 'test condition'?", opts:["a) A specific input value used in a test case","b) A testable aspect of a component or system that may be verified by one or more test cases","c) The precondition that must be satisfied before executing a test","d) A rule that determines whether the system passes or fails"], ans:"b", rationale:"A test condition is an identified aspect of the software that needs to be exercised through testing." },
{ ch:4, lo:"FL-4.2.3", q:"Decision table testing ensures coverage when:", opts:["a) All rows in the table are covered by at least one test case","b) All columns in the table are covered by at least one test case","c) All conditions are set to true in at least one test","d) All boundary values of each condition are tested"], ans:"a", rationale:"Decision table test coverage is achieved when every rule (column/row) is executed by at least one test case." },
{ ch:4, lo:"FL-4.2.4", q:"A system can be in states: Idle, Processing, Error. Events: Start, Complete, Fail, Reset. Which technique tests all valid transitions between these states?", opts:["a) Equivalence partitioning","b) State transition testing","c) Decision table testing","d) Boundary value analysis"], ans:"b", rationale:"State transition testing systematically covers all valid (and optionally invalid) transitions in a state machine." },
{ ch:4, lo:"FL-4.1.2", q:"Which of the following is the CORRECT definition of a 'test case'?", opts:["a) A high-level description of what to test","b) A set of preconditions, inputs, actions, expected results, and postconditions for verifying a specific aspect","c) The document that summarizes all testing activities","d) A single input value and its expected output"], ans:"b", rationale:"A test case includes preconditions, inputs, expected results, and postconditions — fully specifying one test scenario." },
{ ch:4, lo:"FL-4.4.1", q:"Which of the following BEST describes 'checklist-based testing'?", opts:["a) Using a predefined list of test cases for execution","b) Testing guided by a list of items to check, based on experience or standards","c) Reviewing requirements against a checklist for completeness","d) Validating test coverage using a checklist of techniques"], ans:"b", rationale:"Checklist-based testing uses experience-derived lists of what to check, guiding exploratory or scripted testing." },
{ ch:4, lo:"FL-4.3.1", q:"Which coverage metric is MOST suitable for simple, linear code with no branches?", opts:["a) Branch coverage","b) MC/DC coverage","c) Statement coverage","d) Path coverage"], ans:"c", rationale:"For simple linear code without branches, statement coverage is both sufficient and the simplest to measure." },
{ ch:4, lo:"FL-4.1.1", q:"Which of the following describes the difference between 'test design' and 'test implementation'?", opts:["a) Test design creates test cases; test implementation executes them","b) Test design defines what to test; test implementation creates the test scripts and data needed to execute them","c) They are the same activity in modern agile testing","d) Test design is manual; test implementation is automated"], ans:"b", rationale:"Test design produces test cases and conditions; test implementation creates runnable test scripts and prepares data." },
{ ch:4, lo:"FL-4.2.1", q:"Applying equivalence partitioning to a discount system: orders <$100 get 0%, $100-$500 get 10%, >$500 get 20%. How many valid equivalence partitions are there?", opts:["a) 1","b) 2","c) 3","d) 6"], ans:"c", rationale:"There are three valid partitions: <$100 (0%), $100-$500 (10%), >$500 (20%) — each with distinct behavior." },
{ ch:4, lo:"FL-4.3.2", q:"Which of the following coverage techniques is typically required for safety-critical avionics software?", opts:["a) Statement coverage only","b) Modified Condition/Decision Coverage (MC/DC)","c) Equivalence partitioning","d) Branch coverage only"], ans:"b", rationale:"DO-178C requires MC/DC for the highest criticality level (DAL A) avionics software." },
{ ch:4, lo:"FL-4.4.1", q:"A tester designs tests based on their knowledge of common programming mistakes such as off-by-one errors. This is an example of:", opts:["a) Boundary value analysis","b) Equivalence partitioning","c) Error guessing","d) Decision table testing"], ans:"c", rationale:"Error guessing uses tester experience to anticipate where defects are likely — e.g., off-by-one, null pointers." },
{ ch:4, lo:"FL-4.3.1", q:"Which of the following statements about white-box testing is TRUE?", opts:["a) It tests the system from an external user perspective only","b) It uses knowledge of internal code structure to design tests","c) It cannot be automated","d) It is only applicable at the system test level"], ans:"b", rationale:"White-box testing uses knowledge of internal structure (code, architecture) to design tests and measure coverage." },

// Chapter 5
{ ch:5, lo:"FL-5.1.1", q:"Which of the following is a component of a test plan?", opts:["a) Defect reports from previous projects","b) Test schedule, resource plan, and risk assessment","c) Detailed test cases for all features","d) Source code of the system under test"], ans:"b", rationale:"A test plan includes schedule, resources, scope, approach, risks, and criteria — not detailed test cases." },
{ ch:5, lo:"FL-5.3.1", q:"Which metric is MOST useful for monitoring test execution progress?", opts:["a) Lines of code written per day","b) Number of test cases executed vs planned","c) Number of requirements approved","d) Number of developers on the team"], ans:"b", rationale:"Tracking executed vs planned test cases directly shows test execution progress against the schedule." },
{ ch:5, lo:"FL-5.2.1", q:"A risk-based testing approach prioritizes test effort based on:", opts:["a) The order features were developed","b) The likelihood and impact of potential failures","c) The number of requirements per feature","d) The availability of test environments"], ans:"b", rationale:"Risk-based testing allocates effort proportionally to product risk (likelihood x impact of failure)." },
{ ch:5, lo:"FL-5.2.1", q:"Which of the following is an example of a 'product risk' in software testing?", opts:["a) The project may exceed its budget","b) A key tester may leave the project","c) The payment module may incorrectly calculate taxes","d) Test environments may not be available on time"], ans:"c", rationale:"Product risk is the risk of the software failing to meet quality requirements — e.g., incorrect calculations." },
{ ch:5, lo:"FL-5.2.1", q:"Which of the following is an example of a 'project risk'?", opts:["a) The login feature may have a security vulnerability","b) A critical third-party library may not be delivered on time","c) The payment module may process duplicate transactions","d) The API may return incorrect data under load"], ans:"b", rationale:"Project risks threaten the project's success (schedule, resources, budget) — not the product's quality." },
{ ch:5, lo:"FL-5.1.2", q:"Test entry criteria define:", opts:["a) When testing should stop","b) The conditions that must be met before a test phase can begin","c) The expected results for each test case","d) The skills required for each tester on the project"], ans:"b", rationale:"Entry criteria specify what must be in place (build, environment, data, resources) before testing starts." },
{ ch:5, lo:"FL-5.3.2", q:"Which of the following BEST describes a 'test summary report'?", opts:["a) A document listing all planned test cases","b) A report summarizing testing activities, results, and a quality assessment for stakeholders","c) A real-time dashboard of test execution status","d) A log of all test cases executed during a test session"], ans:"b", rationale:"A test summary report provides stakeholders with an overview of what was tested, results, and quality status." },
{ ch:5, lo:"FL-5.2.2", q:"When applying risk-based testing, which feature would receive the HIGHEST test priority?", opts:["a) A rarely used admin configuration page with low business impact","b) A core payment processing module used by all customers","c) A cosmetic UI change to the color scheme","d) A minor spelling correction in the help text"], ans:"b", rationale:"High likelihood of defects x high business impact = highest product risk, highest test priority." },
{ ch:5, lo:"FL-5.5.1", q:"Which of the following is a purpose of defect management in testing?", opts:["a) To eliminate the need for regression testing","b) To track, prioritize, and manage defects through their lifecycle to resolution","c) To automatically fix defects found during testing","d) To measure developer productivity by counting defects"], ans:"b", rationale:"Defect management provides a systematic process for recording, classifying, and resolving found defects." },
{ ch:5, lo:"FL-5.5.1", q:"Which of the following information is typically included in a defect report?", opts:["a) The author's opinion on why the defect occurred","b) Steps to reproduce, actual result, expected result, and severity","c) The cost of fixing the defect","d) The names of developers who may have introduced the defect"], ans:"b", rationale:"A defect report includes reproduction steps, actual vs expected results, severity, and environment details." },
{ ch:5, lo:"FL-5.1.3", q:"Which of the following BEST describes 'test estimation'?", opts:["a) Counting the number of requirements in the specification","b) Predicting the effort, time, and resources needed for testing activities","c) Measuring how many defects will be found during testing","d) Calculating the percentage of code covered by tests"], ans:"b", rationale:"Test estimation forecasts effort, duration, and resources needed to complete testing within project constraints." },
{ ch:5, lo:"FL-5.1.3", q:"The 'percentage of work done' technique for test estimation involves:", opts:["a) Estimating based on the experience of similar past projects","b) Tracking actual effort spent and extrapolating to project completion","c) Dividing requirements into test cases and estimating per test case","d) Using function point analysis to size the testing effort"], ans:"b", rationale:"Percentage of work done tracks actual burn rate and extrapolates remaining effort to predict total duration." },
{ ch:5, lo:"FL-5.1.3", q:"Which of the following is a factor that affects test effort estimation?", opts:["a) The number of project managers on the team","b) Product complexity, team experience, and tool availability","c) The physical location of the development office","d) The color scheme of the application being tested"], ans:"b", rationale:"Product complexity, team experience, available tooling, and environment stability all affect effort estimation." },
{ ch:5, lo:"FL-5.3.1", q:"Which of the following BEST describes 'test control'?", opts:["a) Automating repetitive test execution tasks","b) Taking corrective action when testing deviates from the plan","c) Reviewing the test strategy to update it annually","d) Controlling access to the test environment"], ans:"b", rationale:"Test control involves taking corrective actions (re-prioritizing, adding resources) when progress deviates from plan." },
{ ch:5, lo:"FL-5.1.2", q:"Exit criteria for a test phase TYPICALLY include:", opts:["a) All planned test cases have been executed and all defects have been fixed","b) Achievement of coverage targets and closure of defects above a severity threshold","c) Approval from every stakeholder on the project","d) Zero open defects in the defect tracking system"], ans:"b", rationale:"Practical exit criteria focus on coverage thresholds and severity-based defect resolution — not zero defects." },
{ ch:5, lo:"FL-5.5.1", q:"Which defect attribute describes the importance of fixing the defect relative to business impact?", opts:["a) Severity","b) Priority","c) Status","d) Reproducibility"], ans:"b", rationale:"Priority reflects the business urgency of fixing a defect; severity reflects its technical impact." },
{ ch:5, lo:"FL-5.5.1", q:"A defect is found during system testing that causes data loss. It is classified as 'Critical'. This classification refers to the defect's:", opts:["a) Priority","b) Severity","c) Status","d) Root cause"], ans:"b", rationale:"Severity indicates the technical impact/damage caused by the defect — data loss is Critical severity." },
{ ch:5, lo:"FL-5.5.1", q:"Which of the following is an advantage of using a defect tracking tool?", opts:["a) It automatically fixes defects in the code","b) It provides traceability, history, and communication between testers and developers","c) It eliminates the need for test case management","d) It generates test cases from defect patterns"], ans:"b", rationale:"Defect tracking tools provide a shared record, history, and communication channel for the team." },
{ ch:5, lo:"FL-5.3.1", q:"Which of the following is an example of a test progress metric?", opts:["a) Number of requirements implemented","b) Defect detection percentage (DDP)","c) Number of commits per day","d) Average build duration"], ans:"b", rationale:"DDP (defects found in testing / total defects found) is a quality metric measuring testing effectiveness." },
{ ch:5, lo:"FL-5.1.3", q:"A tester estimates test effort using three-point estimation: best case 5 days, most likely 10 days, worst case 21 days. Using PERT formula (B+4M+W)/6, what is the estimate?", opts:["a) 10 days","b) 11 days","c) 12 days","d) 15 days"], ans:"b", rationale:"PERT: (5 + 4x10 + 21)/6 = (5 + 40 + 21)/6 = 66/6 = 11 days." },
{ ch:5, lo:"FL-5.2.2", q:"Which of the following is the PRIMARY purpose of test case prioritization?", opts:["a) To make the test plan look more organized","b) To maximize defect detection early, especially given time or resource constraints","c) To ensure automated tests run before manual tests","d) To assign test cases to individual testers fairly"], ans:"b", rationale:"Prioritization runs highest-value tests first so that if time runs out, the most important areas are covered." },
{ ch:5, lo:"FL-5.1.1", q:"A 'test strategy' differs from a 'test plan' in that:", opts:["a) A test plan is project-specific; a test strategy is a higher-level organizational document","b) A test strategy lists individual test cases; a test plan defines the overall approach","c) A test strategy is written by testers; a test plan is written by managers","d) A test plan is used for agile projects; a test strategy for waterfall projects"], ans:"a", rationale:"A test strategy is a high-level organizational policy; a test plan tailors the strategy to a specific project." },
{ ch:5, lo:"FL-5.2.1", q:"Which of the following factors would increase product risk in a software project?", opts:["a) An experienced team with domain expertise","b) Well-defined, stable requirements","c) Novel technology with which the team has no prior experience","d) A short, simple code base with high test coverage"], ans:"c", rationale:"New/unfamiliar technology increases the likelihood of defects, thus increasing product risk." },
{ ch:5, lo:"FL-5.1.1", q:"Which of the following is a 'cost of quality' consideration in testing?", opts:["a) The cost of purchasing test automation tools","b) The cost of finding defects in testing vs the cost of failures in production","c) The salary cost of hiring more developers","d) The infrastructure cost of running test environments"], ans:"b", rationale:"Cost of quality compares prevention/appraisal costs (testing) against failure costs (production defects)." },

// Chapter 6
{ ch:6, lo:"FL-6.1.1", q:"Which of the following is an example of a test execution tool?", opts:["a) A requirements management tool","b) A test automation framework like Selenium","c) A defect tracking tool like Jira","d) A test data generation tool"], ans:"b", rationale:"Test execution tools (like Selenium) run tests automatically against the system under test." },
{ ch:6, lo:"FL-6.1.1", q:"Which of the following BEST describes the purpose of a test management tool?", opts:["a) To automate test execution","b) To plan, monitor, and control testing activities and store test assets","c) To generate test data for performance tests","d) To analyze code for security vulnerabilities"], ans:"b", rationale:"Test management tools (e.g., TestRail) organize test plans, cases, results, and track coverage and metrics." },
{ ch:6, lo:"FL-6.2.1", q:"Which of the following is a potential RISK of test automation?", opts:["a) Tests run faster than manual testing","b) Automated tests may provide false confidence if they test the wrong things","c) Automation requires no maintenance after initial setup","d) Automation finds more defects than manual testing in all cases"], ans:"b", rationale:"Automation risk: tests may pass but miss real defects if poorly designed, creating unjustified confidence." },
{ ch:6, lo:"FL-6.1.1", q:"Which type of tool is MOST appropriate for measuring how much of the source code is exercised by tests?", opts:["a) A defect tracking tool","b) A code coverage tool","c) A performance testing tool","d) A requirements management tool"], ans:"b", rationale:"Code coverage tools instrument source code and report how much is exercised by the test suite." },
{ ch:6, lo:"FL-6.2.1", q:"Which of the following is a factor to consider when introducing a test automation tool to an organization?", opts:["a) Whether the tool uses the same programming language as the product","b) Total cost of ownership, learning curve, and integration with existing tools","c) Whether the CEO approves of the vendor","d) The color of the tool's user interface"], ans:"b", rationale:"Tool introduction requires assessing TCO (license, training, maintenance), integration fit, and team capability." },
{ ch:6, lo:"FL-6.1.1", q:"Which of the following BEST describes a CI/CD pipeline in the context of test tools?", opts:["a) A manual process for deploying software to production","b) An automated system that builds, tests, and deploys software continuously on code changes","c) A project management methodology for organizing sprints","d) A set of tools specifically for performance testing"], ans:"b", rationale:"A CI/CD pipeline automates build, test, and deployment steps, enabling rapid and safe delivery." },
{ ch:6, lo:"FL-6.2.1", q:"Which of the following is a benefit of test automation?", opts:["a) Automated tests always find more defects than manual tests","b) Repeatability and speed of execution, enabling more frequent regression testing","c) Elimination of the need for test case design","d) Automated tests require no maintenance once created"], ans:"b", rationale:"Automation provides fast, repeatable regression execution — enabling more frequent testing without proportional effort." },
{ ch:6, lo:"FL-6.1.1", q:"A tester wants to simulate thousands of concurrent users to test system performance. Which type of tool is MOST appropriate?", opts:["a) Test management tool","b) Static analysis tool","c) Performance testing tool","d) Defect tracking tool"], ans:"c", rationale:"Performance testing tools (e.g., JMeter, Gatling) simulate concurrent load to test system performance." },
{ ch:6, lo:"FL-6.1.1", q:"Which of the following is an example of a STATIC analysis tool?", opts:["a) Selenium WebDriver","b) SonarQube","c) JMeter","d) TestRail"], ans:"b", rationale:"SonarQube performs static code analysis — examining code without executing it to find quality issues." },
{ ch:6, lo:"FL-6.2.1", q:"Which of the following statements about selecting a test automation tool is CORRECT?", opts:["a) The most expensive tool is always the best choice","b) The tool should be evaluated against specific project needs, technical context, and team skills","c) All test automation tools are equivalent in capability","d) Tools should be selected based solely on popularity in the industry"], ans:"b", rationale:"Tool selection must match project requirements, technical stack, team capability, and integration needs." },
{ ch:6, lo:"FL-6.2.1", q:"Which of the following is a DISADVANTAGE of test automation?", opts:["a) Tests run faster than manual execution","b) High initial investment in tool setup, scripting, and maintenance","c) Tests can be run at any time without human intervention","d) Automated tests can be version-controlled like code"], ans:"b", rationale:"Automation requires upfront investment in tool setup, test script development, and ongoing maintenance." },
{ ch:6, lo:"FL-6.1.1", q:"Which of the following describes 'keyword-driven testing' in test automation?", opts:["a) Tests are written entirely in source code by developers","b) Tests use keywords (actions) defined in a table that are interpreted by an automation framework","c) Tests are generated automatically from requirements keywords","d) Tests are driven by performance metrics and thresholds"], ans:"b", rationale:"Keyword-driven testing separates test logic from scripts; non-programmers can write tests using defined keywords." },
{ ch:6, lo:"FL-6.1.1", q:"Which of the following is the MAIN advantage of using virtual test environments over physical ones?", opts:["a) Virtual environments always run faster than physical hardware","b) They can be quickly provisioned, replicated, and reset to a known state on demand","c) They eliminate the need for test data management","d) They guarantee identical behavior to production environments"], ans:"b", rationale:"Virtual environments (VMs, containers) can be spun up quickly, cloned, and reset — reducing setup time and cost." },
{ ch:6, lo:"FL-6.2.1", q:"Which of the following BEST describes the 'maintainability' challenge of test automation?", opts:["a) Automated tests are difficult to run on different operating systems","b) Automated test scripts must be updated whenever the application under test changes","c) Automation tools require expensive hardware to run","d) Automated tests can only be maintained by the original author"], ans:"b", rationale:"Maintenance burden is a key challenge: UI changes, API changes, and refactoring can break automated tests." },
{ ch:6, lo:"FL-6.1.1", q:"A test team wants to automate API tests to validate backend services. Which tool type is MOST appropriate?", opts:["a) UI automation tool (e.g., Selenium)","b) API testing tool (e.g., Postman, RestAssured)","c) Performance testing tool (e.g., JMeter)","d) Static analysis tool (e.g., SonarQube)"], ans:"b", rationale:"API testing tools send HTTP requests and validate responses directly against backend services." },
{ ch:6, lo:"FL-6.2.1", q:"Which of the following BEST explains why not all testing can or should be automated?", opts:["a) Test automation tools are not mature enough yet","b) Some tests (e.g., usability, exploratory) require human judgment and observation","c) Automation is more expensive than manual testing in all cases","d) Regulatory requirements prohibit automated testing"], ans:"b", rationale:"Usability, exploratory, and intuition-based tests require human cognitive abilities that automation cannot replicate." },
];

// ============================================================
// PART 2 QUESTIONS (87)
// ============================================================
const part2 = [
{ ch:1, lo:"FL-1.1.1", q:"Which of the following is NOT a typical test objective?", opts:["a) Preventing defects by evaluating work products","b) Verifying that all specified requirements have been fulfilled","c) Guaranteeing the absence of all defects after release","d) Providing information to stakeholders for go/no-go decisions"], ans:"c", rationale:"Testing cannot guarantee defect-free software. Guaranteeing absence of all defects is not a realistic or valid objective." },
{ ch:1, lo:"FL-1.1.1", q:"A tester is assigned to evaluate a requirements document before development begins. Which test objective does this BEST support?", opts:["a) Validating the completed system against user needs","b) Preventing defects by catching ambiguities before they enter code","c) Measuring code coverage of implemented functionality","d) Confirming that a previously fixed defect does not recur"], ans:"b", rationale:"Reviewing requirements prevents defects by finding problems before development begins — a key preventive test objective." },
{ ch:1, lo:"FL-1.2.1", q:"Which of the following BEST distinguishes 'validation' from 'verification'?", opts:["a) Verification checks whether we built the right product; validation checks whether we built the product right","b) Validation checks whether the product meets the specification; verification checks whether it meets user needs","c) Verification checks whether we built the product right; validation checks whether we built the right product","d) They are synonyms used interchangeably in quality management"], ans:"c", rationale:"Verification = built it right (meets spec). Validation = built the right thing (meets user needs)." },
{ ch:1, lo:"FL-1.2.1", q:"Which of the following activities is classified as 'dynamic testing'?", opts:["a) Reviewing a test plan for completeness","b) Running a test suite against a deployed build","c) Performing a code walkthrough with the development team","d) Checking a requirements document for ambiguities"], ans:"b", rationale:"Dynamic testing requires executing the software. Running a test suite against a build is dynamic testing." },
{ ch:1, lo:"FL-1.2.2", q:"Which of the following BEST describes how testing contributes to quality assurance (QA)?", opts:["a) Testing directly prevents developers from making mistakes","b) Test results provide feedback used to improve processes, reducing future defects","c) Testing replaces all other QA activities in mature organizations","d) QA uses test results only for go/no-go release decisions"], ans:"b", rationale:"Test results feed into QA process improvement — defect data and lessons learned help prevent future defects." },
{ ch:1, lo:"FL-1.2.3", q:"A developer writes incorrect code because the requirement was ambiguous. This sequence represents:", opts:["a) Failure to defect to error","b) Error to defect to failure (potential)","c) Defect to error to failure","d) Root cause to failure to defect"], ans:"b", rationale:"The human error (misreading the ambiguous requirement) creates a defect in the code, which may eventually cause a failure when executed." },
{ ch:1, lo:"FL-1.2.3", q:"Which term describes a flaw in a work product that may cause the product to fail to perform its required function?", opts:["a) Failure","b) Error","c) Defect","d) Incident"], ans:"c", rationale:"A defect (fault/bug) is a flaw in a work product. An error is the human action that caused it; a failure is the observable incorrect behavior." },
{ ch:1, lo:"FL-1.4.1", q:"During which test activity would a tester create test scripts and set up test data?", opts:["a) Test planning","b) Test analysis","c) Test design","d) Test implementation"], ans:"d", rationale:"Test implementation transforms test cases into executable test scripts and prepares test data, environments, and harnesses." },
{ ch:1, lo:"FL-1.4.1", q:"A tester is reviewing test results and writing a test summary report. Which test activity is this?", opts:["a) Test execution","b) Test monitoring","c) Test completion","d) Test control"], ans:"c", rationale:"Test completion includes producing the summary report, archiving test assets, and deriving lessons learned." },
{ ch:1, lo:"FL-1.5.3", q:"Which of the following is a DISADVANTAGE of full independence in testing?", opts:["a) Independent testers may find more defects than embedded testers","b) Communication gaps between developers and testers can slow defect resolution","c) Independent testers bring different perspectives to testing","d) Independent testing removes confirmation bias from the original author"], ans:"b", rationale:"Full independence risks communication silos — without collaboration, context is lost and feedback loops slow down." },
{ ch:1, lo:"FL-1.5.3", q:"Which level of independence involves developers testing their own code?", opts:["a) No independence","b) Independence within the team","c) Independence from the development team","d) Independence from the organization"], ans:"a", rationale:"No independence = developers test their own code. Higher independence levels involve separate team members, teams, or organizations." },
{ ch:1, lo:"FL-1.5.4", q:"In the 'whole team' approach, which of the following BEST describes the role of business representatives?", opts:["a) Business representatives manage the test team's daily activities","b) Business representatives define acceptance criteria and provide domain knowledge","c) Business representatives are responsible for test environment setup","d) Business representatives conduct static analysis of the source code"], ans:"b", rationale:"In the whole team approach, business representatives (e.g., product owners) define acceptance criteria and answer domain questions." },
{ ch:1, lo:"FL-1.5.4", q:"Which of the following BEST illustrates the 'whole team approach' to quality?", opts:["a) Only the QA team is responsible for finding defects","b) Quality is everyone's responsibility — developers, testers, and business reps collaborate throughout","c) The test manager owns quality while developers focus solely on coding","d) Developers and testers work in separate streams with handoffs at milestones"], ans:"b", rationale:"The whole team approach means everyone on the team shares responsibility for quality, not just dedicated testers." },
{ ch:2, lo:"FL-2.1.2", q:"In Agile, what is the PRIMARY purpose of the sprint review (demo)?", opts:["a) To plan the test cases for the next sprint","b) To inspect the increment and adapt the product backlog based on stakeholder feedback","c) To retrospectively assess the team's testing processes","d) To formally accept the sprint deliverables for release"], ans:"b", rationale:"The sprint review is an inspection event where stakeholders see the increment and provide feedback to adapt the backlog." },
{ ch:2, lo:"FL-2.1.2", q:"In Scrum, who is primarily responsible for maintaining the product backlog?", opts:["a) Scrum Master","b) Development team","c) Product Owner","d) Test Manager"], ans:"c", rationale:"The Product Owner owns and prioritizes the product backlog in Scrum." },
{ ch:2, lo:"FL-2.1.3", q:"In TDD, what is the correct sequence of steps?", opts:["a) Write code, write test, refactor","b) Write test, write minimal code to pass, refactor","c) Refactor, write test, write code","d) Write test, refactor, write code"], ans:"b", rationale:"TDD follows Red-Green-Refactor: write a failing test, write minimal code to pass it, then refactor for quality." },
{ ch:2, lo:"FL-2.1.3", q:"Which of the following BEST distinguishes BDD from TDD?", opts:["a) BDD uses code-level unit tests; TDD uses business-readable scenarios","b) BDD focuses on system behavior expressed in business language; TDD focuses on code-level unit behavior","c) TDD is only for developers; BDD is only for testers","d) BDD replaces all other forms of testing; TDD does not"], ans:"b", rationale:"BDD emphasizes business-readable behavior specifications (Given/When/Then) enabling non-technical collaboration; TDD focuses on code-level unit testing." },
{ ch:2, lo:"FL-2.1.3", q:"A team writes acceptance criteria in Given/When/Then format before development begins, then uses them as executable tests. This approach is BEST described as:", opts:["a) Test-Driven Development (TDD)","b) Acceptance Test-Driven Development (ATDD)","c) Exploratory testing","d) Risk-based testing"], ans:"b", rationale:"ATDD uses acceptance criteria written upfront (often in Given/When/Then) as executable tests to drive development." },
{ ch:2, lo:"FL-2.2.1", q:"Which of the following is a test basis TYPICALLY used at the component (unit) test level?", opts:["a) System requirements specification","b) User acceptance criteria","c) Detailed design documentation and source code","d) Business process flows and use cases"], ans:"c", rationale:"Component testing uses detailed design documents and source code as the test basis since it tests individual units." },
{ ch:2, lo:"FL-2.2.2", q:"Which of the following defect types is MOST likely to be found during component integration testing?", opts:["a) Incorrect algorithm logic within a single function","b) Incorrect data passed between two modules via an interface","c) A business rule not correctly implemented across the whole system","d) A usability issue in the application's user interface"], ans:"b", rationale:"Component integration testing focuses on interface contracts — incorrect data between modules is the classic defect type." },
{ ch:2, lo:"FL-2.2.3", q:"Which of the following is a typical TEST BASIS used at system test level?", opts:["a) Component-level unit tests","b) System requirements specification, use cases, and user stories","c) Source code and detailed design documents","d) Acceptance criteria from the product owner only"], ans:"b", rationale:"System testing uses the system requirements specification, functional specs, use cases, and risk analyses as its test basis." },
{ ch:2, lo:"FL-2.2.3", q:"System testing is PRIMARILY performed by:", opts:["a) Developers testing their own code","b) An independent test team against the full integrated system","c) End users in their production environment","d) Operations staff validating deployment procedures"], ans:"b", rationale:"System testing is typically done by an independent test team against the complete, integrated system in a test environment." },
{ ch:2, lo:"FL-2.2.4", q:"A financial services company must verify that its trading system complies with securities regulations before go-live. Which acceptance test type is MOST appropriate?", opts:["a) Alpha testing","b) Beta testing","c) Operational acceptance testing","d) Regulatory acceptance testing"], ans:"d", rationale:"Regulatory acceptance testing verifies compliance with laws, regulations, and standards governing the domain." },
{ ch:2, lo:"FL-2.2.4", q:"User Acceptance Testing (UAT) is PRIMARILY focused on:", opts:["a) Verifying technical performance under load","b) Validating that the system meets the business needs of end users","c) Detecting code-level defects in individual modules","d) Confirming that security vulnerabilities have been remediated"], ans:"b", rationale:"UAT validates that the system satisfies user needs and is fit for purpose from a business perspective." },
{ ch:2, lo:"FL-2.3.1", q:"Which of the following BEST explains why test environment management is important?", opts:["a) Test environments determine the test strategy used in a project","b) Uncontrolled environments can cause test results to be unreliable or non-reproducible","c) Test environments replace the need for configuration management","d) Environments directly control the number of defects found"], ans:"b", rationale:"Environment instability or differences cause false failures and make defects hard to reproduce — reliable environments are essential." },
{ ch:2, lo:"FL-2.3.1", q:"A test team is running tests but getting inconsistent results — sometimes the same test passes, sometimes it fails. The code has not changed. What is the MOST likely cause?", opts:["a) The test cases have poor expected results","b) The test environment is unstable or misconfigured","c) The testers are not skilled enough to execute the tests","d) The defect tracking tool is recording results incorrectly"], ans:"b", rationale:"Inconsistent results with unchanged code typically point to environment issues: unstable services, shared state, or misconfiguration." },
{ ch:2, lo:"FL-2.3.2", q:"A test team is checking how long the system takes to respond to user actions under a load of 1,000 concurrent users. This is an example of:", opts:["a) Functional testing","b) Security testing","c) Performance efficiency testing","d) Maintainability testing"], ans:"c", rationale:"Response time under concurrent load is a performance efficiency quality characteristic per ISO 25010." },
{ ch:2, lo:"FL-2.3.2", q:"Which of the following is an example of a FUNCTIONAL test type?", opts:["a) Load testing the checkout process under 500 concurrent users","b) Testing that a user can successfully complete a purchase from cart to confirmation","c) Verifying that the application recovers within 30 seconds after a crash","d) Checking that the UI color contrast meets WCAG accessibility standards"], ans:"b", rationale:"Functional testing verifies what the system does — completing a purchase tests the functional behavior of the checkout process." },
{ ch:2, lo:"FL-2.3.2", q:"Which of the following is a NON-functional quality characteristic as defined by ISO 25010?", opts:["a) Correctness","b) Reliability","c) Completeness","d) Traceability"], ans:"b", rationale:"Reliability (including availability, fault tolerance, recoverability) is a non-functional quality characteristic in ISO 25010." },
{ ch:2, lo:"FL-2.3.2", q:"Testing that verifies how easy the system is to understand, learn, and operate is testing which quality characteristic?", opts:["a) Performance efficiency","b) Security","c) Usability","d) Portability"], ans:"c", rationale:"Usability covers learnability, operability, user interface aesthetics, and user error protection." },
{ ch:2, lo:"FL-2.4.1", q:"Which of the following triggers maintenance testing?", opts:["a) Writing the system requirements specification","b) Migrating a legacy application to a new operating system","c) Planning the initial project test strategy","d) Designing the system architecture"], ans:"b", rationale:"Maintenance testing is triggered by changes to an operational system — migration is a classic maintenance trigger." },
{ ch:2, lo:"FL-2.4.1", q:"Which of the following BEST describes 'retirement testing' in the context of maintenance testing?", opts:["a) Testing performed when a senior tester leaves the project","b) Testing to ensure data can be migrated or archived when a system is decommissioned","c) Testing to validate that the system is ready for production deployment","d) Testing performed once a year regardless of changes"], ans:"b", rationale:"Retirement testing ensures data migration, archiving, or handover is correct when a system is being decommissioned." },
{ ch:2, lo:"FL-2.4.1", q:"Why is impact analysis particularly challenging for legacy systems?", opts:["a) Legacy systems always have more users than modern systems","b) Poor documentation and high coupling make it hard to determine what a change will affect","c) Legacy systems use programming languages that cannot be tested","d) Impact analysis tools do not support legacy systems"], ans:"b", rationale:"Legacy systems often lack documentation and have high coupling — making it very difficult to trace the impact of changes." },
{ ch:2, lo:"FL-2.1.4", q:"In a CI/CD pipeline, test automation at which level provides the FASTEST feedback to developers?", opts:["a) System integration tests","b) End-to-end UI tests","c) Unit/component tests","d) User acceptance tests"], ans:"c", rationale:"Unit/component tests run in seconds — they provide the fastest feedback in the CI/CD pipeline (bottom of the test pyramid)." },
{ ch:2, lo:"FL-2.1.5", q:"A team adopts shift-left by having testers review user stories before a sprint begins. What is the PRIMARY benefit?", opts:["a) Testers can write more automated tests during the sprint","b) Ambiguities and missing acceptance criteria are identified before development starts","c) The sprint velocity increases because developers write less code","d) Testers can skip system testing since stories are pre-reviewed"], ans:"b", rationale:"Reviewing stories before the sprint finds gaps and ambiguities early — preventing costly defects from being coded in." },
{ ch:3, lo:"FL-3.1.2", q:"Which of the following defect types is MORE efficiently found by static testing than by dynamic testing?", opts:["a) Race conditions under high concurrency","b) Performance degradation under load","c) Contradictory requirements in two different sections of the specification","d) Incorrect output for a specific combination of inputs"], ans:"c", rationale:"Contradictory requirements can only be found by reading and analyzing the document — dynamic testing cannot directly reveal requirements conflicts." },
{ ch:3, lo:"FL-3.1.2", q:"A team performs peer code reviews before merging to the main branch. Which quality benefit is MOST directly achieved?", opts:["a) Complete functional test coverage of the reviewed code","b) Early detection of coding standard violations and logic errors before dynamic testing","c) Automatic verification that acceptance criteria are met","d) Replacement of integration testing with the review process"], ans:"b", rationale:"Code reviews find coding standards violations, logic errors, and maintainability issues early and cheaply." },
{ ch:3, lo:"FL-3.1.2", q:"Which of the following work products can be examined by static testing?", opts:["a) Runtime logs from production","b) User stories, design documents, and source code","c) Load test performance reports","d) System crash dumps"], ans:"b", rationale:"Static testing applies to any written artifact: user stories, designs, architecture docs, code, test plans, and more." },
{ ch:3, lo:"FL-3.2.1", q:"A team conducts a review where the author presents the document and the team asks questions, raises defects, and discusses improvements collaboratively. There is no formal moderator. This BEST describes a:", opts:["a) Formal inspection","b) Technical review","c) Walkthrough","d) Informal pair review"], ans:"c", rationale:"A walkthrough is author-led, collaborative, informal, and aims at learning and finding defects — no trained moderator required." },
{ ch:3, lo:"FL-3.2.1", q:"Which review type would be MOST appropriate for checking a critical safety specification against a defined standard with formal defect logging and metrics collection?", opts:["a) Informal review","b) Walkthrough","c) Technical review","d) Inspection"], ans:"d", rationale:"Inspection is the most rigorous review type — formal process, trained moderator, defined roles, metrics, and exit criteria." },
{ ch:3, lo:"FL-3.2.1", q:"Which of the following review types requires a trained moderator to facilitate the meeting?", opts:["a) Informal review","b) Walkthrough","c) Inspection","d) Peer review"], ans:"c", rationale:"Inspection requires a trained moderator (facilitator) to ensure the process is followed correctly." },
{ ch:3, lo:"FL-3.2.2", q:"During which phase of a formal review process does the review team identify defects and classify them?", opts:["a) Planning","b) Review initiation","c) Individual review (preparation)","d) Communication and analysis (review meeting)"], ans:"d", rationale:"Defects are communicated, discussed, and classified during the review meeting (communication and analysis phase)." },
{ ch:3, lo:"FL-3.2.2", q:"What is the PURPOSE of the 'review initiation' phase in a formal review?", opts:["a) To fix defects found during individual preparation","b) To distribute the document and ensure everyone has access to materials and understands their role","c) To present the final review findings to management","d) To select which documents will be reviewed in the project"], ans:"b", rationale:"Review initiation distributes materials, confirms participants are ready, and clarifies objectives and logistics." },
{ ch:3, lo:"FL-3.2.2", q:"After a formal review meeting, the author is responsible for:", opts:["a) Writing the review report and distributing it to stakeholders","b) Fixing or addressing the defects identified during the review","c) Facilitating the follow-up meeting","d) Deciding which defects are valid before any fixes are made"], ans:"b", rationale:"After the review meeting, the author fixes the defects; the moderator typically checks that fixes are made (rework phase)." },
{ ch:3, lo:"FL-3.2.3", q:"In a formal review, who is responsible for documenting issues raised during the review meeting?", opts:["a) Author","b) Moderator","c) Scribe","d) Reviewer"], ans:"c", rationale:"The scribe records all defects, issues, decisions, and action items during the formal review meeting." },
{ ch:3, lo:"FL-3.2.3", q:"Which review role is responsible for providing the work product to be reviewed and clarifying unclear points during the review?", opts:["a) Moderator","b) Author","c) Scribe","d) Review leader"], ans:"b", rationale:"The author provides the work product and should be available to answer questions, though should not dominate discussion." },
{ ch:3, lo:"FL-3.2.4", q:"Which of the following behaviors would UNDERMINE the success of a formal review?", opts:["a) Having clear, agreed objectives before the review starts","b) Selecting the right reviewers with appropriate expertise","c) Managers using defect counts from reviews to evaluate developer performance","d) Using checklists to guide individual review preparation"], ans:"c", rationale:"Using review defect data to evaluate individuals creates a blame culture — reviewers and authors become defensive, destroying review effectiveness." },
{ ch:3, lo:"FL-3.2.4", q:"Which of the following is a SUCCESS FACTOR for formal reviews?", opts:["a) Inviting as many stakeholders as possible to ensure broad coverage","b) Conducting the review meeting as fast as possible to minimize cost","c) Ensuring the work product has met entry criteria before the review starts","d) Having the author fix all defects during the review meeting"], ans:"c", rationale:"Checking entry criteria prevents waste — reviewers should not spend time on a document that is incomplete or unstable." },
{ ch:3, lo:"FL-3.2.4", q:"Which of the following is a KEY success factor for reviews?", opts:["a) All reviewers must be certified software testers","b) Organizational support and management commitment to the review process","c) Reviews must always be conducted face-to-face","d) The author must agree with all defects raised by reviewers"], ans:"b", rationale:"Management commitment ensures time is allocated, reviews are valued, and findings are acted upon — critical for success." },
{ ch:4, lo:"FL-4.2.1", q:"A form field accepts numeric values from 1 to 99 (integers, inclusive). Applying equivalence partitioning, which of the following sets represents the MINIMUM test inputs (one per partition)?", opts:["a) 0, 50, 100","b) 1, 99","c) -1, 50, 100","d) 0, 1, 99, 100"], ans:"a", rationale:"Three partitions: invalid below (e.g., 0), valid (e.g., 50), invalid above (e.g., 100). One representative per partition is sufficient." },
{ ch:4, lo:"FL-4.2.1", q:"A discount system applies: no discount for purchases under £50, 10% for £50-£199, 20% for £200 and above. Using equivalence partitioning with 2-value BVA, which set of test values provides the BEST coverage of boundaries?", opts:["a) £49, £50, £199, £200","b) £25, £100, £300","c) £50, £199","d) £49, £50, £100, £199, £200, £201"], ans:"d", rationale:"2-value BVA on each boundary: £49/£50 (first boundary), £199/£200 (second boundary), plus a value within each partition. Option d covers all boundaries." },
{ ch:4, lo:"FL-4.2.2", q:"A password field accepts 8-16 characters. Using 3-value BVA, which values should be tested?", opts:["a) 7, 8, 9, 15, 16, 17","b) 8, 16","c) 7, 8, 16, 17","d) 1, 8, 12, 16, 20"], ans:"a", rationale:"3-value BVA: for lower boundary (8): 7, 8, 9. For upper boundary (16): 15, 16, 17. Six values in total." },
{ ch:4, lo:"FL-4.2.3", q:"A decision table has 3 binary conditions. What is the MAXIMUM number of rules (columns) in the full decision table?", opts:["a) 3","b) 6","c) 8","d) 9"], ans:"c", rationale:"With 3 binary conditions, the number of possible combinations is 2 to the power of 3 = 8 rules." },
{ ch:4, lo:"FL-4.2.3", q:"Which of the following is a LIMITATION of decision table testing?", opts:["a) It cannot be used for functional testing","b) Tables can become very large when there are many conditions","c) Decision tables cannot be derived from requirements","d) Decision tables only work for numeric input conditions"], ans:"b", rationale:"Decision tables grow exponentially with conditions (2 to the power of n). Many conditions create unwieldy tables requiring collapse techniques." },
{ ch:4, lo:"FL-4.2.4", q:"A system has states: S1 (Idle), S2 (Active), S3 (Suspended), S4 (Terminated). What does testing 'all transitions' require?", opts:["a) Testing only the valid transitions (Start, Suspend, Resume, Stop)","b) Testing every valid transition at least once plus all invalid transitions","c) Testing only the happy path: S1 to S2 to S4","d) Testing one path that visits all states"], ans:"a", rationale:"All-transitions coverage requires every valid transition to be exercised at least once. Testing invalid transitions is an additional optional level." },
{ ch:4, lo:"FL-4.2.4", q:"Which test design technique is BEST suited to test a vending machine that behaves differently based on whether coins have been inserted and whether a product is selected?", opts:["a) Equivalence partitioning","b) Decision table testing","c) State transition testing","d) Boundary value analysis"], ans:"c", rationale:"A vending machine's behavior depends on its current state (coins inserted, product selected) — state transition testing models this directly." },
{ ch:4, lo:"FL-4.3.1", q:"A module has 10 executable statements. After testing, 8 statements have been executed. What is the statement coverage?", opts:["a) 10%","b) 20%","c) 80%","d) 90%"], ans:"c", rationale:"Statement coverage = executed statements / total statements = 8/10 = 80%." },
{ ch:4, lo:"FL-4.3.1", q:"Which of the following code constructs CANNOT be revealed as untested by statement coverage but CAN be revealed by branch coverage?", opts:["a) An unreachable function","b) A decision whose false branch is never taken","c) A variable that is never initialized","d) A loop body that is never entered"], ans:"b", rationale:"If a decision always evaluates to true, the false branch is never executed. Statement coverage misses this; branch coverage requires both true and false outcomes." },
{ ch:4, lo:"FL-4.3.2", q:"A function has two decisions. After testing, all branches have been exercised. What level of coverage has been achieved?", opts:["a) Statement coverage only","b) Branch coverage","c) Path coverage","d) MC/DC coverage"], ans:"b", rationale:"Exercising all true/false outcomes of every decision achieves 100% branch (decision) coverage." },
{ ch:4, lo:"FL-4.3.2", q:"Which of the following BEST describes Modified Condition/Decision Coverage (MC/DC)?", opts:["a) Every statement in the code is executed at least once","b) Every condition in a decision independently affects the decision outcome","c) All branches of all decisions are exercised","d) All paths through the code are executed"], ans:"b", rationale:"MC/DC requires each condition in a compound decision to independently demonstrate it can affect the overall decision outcome." },
{ ch:4, lo:"FL-4.4.1", q:"A tester with 10 years of domain experience designs tests for a financial calculation module without any specification, relying on intuition about common errors. This is BEST described as:", opts:["a) Boundary value analysis","b) Error guessing","c) Exploratory testing","d) Checklist-based testing"], ans:"b", rationale:"Error guessing uses tester experience and intuition to anticipate likely defects without following a formal technique." },
{ ch:4, lo:"FL-4.4.1", q:"Which of the following BEST describes 'session-based exploratory testing'?", opts:["a) Ad-hoc testing with no time limit or objectives","b) Structured, time-boxed testing guided by a charter, with a session report produced afterward","c) Automated testing using recorded user sessions","d) Scripted testing where every step is pre-defined in a test case"], ans:"b", rationale:"Session-based exploratory testing uses time-boxes, charters (mission statements), and session notes for accountability." },
{ ch:4, lo:"FL-4.4.1", q:"Experience-based test techniques include which of the following?", opts:["a) Equivalence partitioning and BVA","b) Error guessing, exploratory testing, and checklist-based testing","c) Statement coverage and branch coverage","d) State transition testing and decision table testing"], ans:"b", rationale:"Experience-based techniques (error guessing, exploratory testing, checklist-based testing) rely on tester knowledge and intuition rather than formal models." },
{ ch:5, lo:"FL-5.1.4", q:"Which test case prioritization approach runs the tests that have the HIGHEST likelihood of finding defects first?", opts:["a) Random prioritization","b) Risk-based prioritization","c) Chronological prioritization","d) Alphabetical prioritization by feature name"], ans:"b", rationale:"Risk-based prioritization orders tests by their potential to find high-impact defects in high-risk areas first." },
{ ch:5, lo:"FL-5.1.4", q:"Which test case prioritization approach runs the tests that have the HIGHEST likelihood of finding defects first?", opts:["a) Random prioritization","b) Risk-based prioritization","c) Chronological prioritization","d) Alphabetical prioritization by feature name"], ans:"b", rationale:"Risk-based prioritization orders tests by their potential to find high-impact defects in high-risk areas first." },
{ ch:5, lo:"FL-5.1.4", q:"A team has limited time for regression testing before release. They decide to run tests covering the most recently changed code first. This is an example of:", opts:["a) Coverage-based prioritization","b) Requirements-based prioritization","c) Change-related prioritization","d) Random test selection"], ans:"c", rationale:"Prioritizing tests for recently changed code is change-related prioritization — targeting the most likely regression areas." },
{ ch:5, lo:"FL-5.1.4", q:"Which of the following factors should influence test case PRIORITIZATION?", opts:["a) The number of lines in the test script","b) Business value, risk level, and probability of failure","c) The alphabetical order of test case names","d) The order in which test cases were written"], ans:"b", rationale:"Prioritization should reflect business impact, risk exposure, and defect likelihood — not administrative factors." },
{ ch:5, lo:"FL-5.4.1", q:"What is the PRIMARY purpose of configuration management in the context of testing?", opts:["a) To automate the execution of all test cases","b) To ensure that test items, test environments, and test documentation are identified, controlled, and traceable","c) To manage the team's project schedule and milestones","d) To provide a central repository for all defect reports"], ans:"b", rationale:"Configuration management identifies, controls, and maintains integrity of all work products including test items and environments." },
{ ch:5, lo:"FL-5.4.1", q:"A tester executes a test case and later cannot reproduce the result because they do not know which version of the software or test data was used. Which process failure caused this?", opts:["a) Inadequate test planning","b) Poor configuration management","c) Lack of test automation","d) Insufficient defect reporting"], ans:"b", rationale:"Configuration management ensures version control of software, test data, environments, and test artifacts for reproducibility." },
{ ch:5, lo:"FL-5.4.1", q:"Which of the following is an example of a configuration item in the context of testing?", opts:["a) A meeting minutes document from the project kickoff","b) A specific version of the test environment including OS, database, and application build","c) The project manager's resource allocation spreadsheet","d) A whiteboard diagram from a design session"], ans:"b", rationale:"Configuration items are managed artifacts: specific versions of software builds, test environments, test scripts, and data sets." },
{ ch:5, lo:"FL-5.5.2", q:"What is the TYPICAL lifecycle status sequence of a defect?", opts:["a) New, Assigned, Fixed, Verified, Closed","b) Open, Closed, Reopened, Verified","c) Found, Reported, Ignored, Fixed","d) New, Rejected, Fixed, Closed"], ans:"a", rationale:"A typical defect lifecycle: New (raised), Assigned (to developer), Fixed, Verified (by tester), Closed." },
{ ch:5, lo:"FL-5.5.2", q:"A tester re-tests a defect after a fix and finds the original behavior is still present. What status should the defect report be set to?", opts:["a) Closed","b) Duplicate","c) Reopened","d) Deferred"], ans:"c", rationale:"If a defect recurs after a fix, it is reopened — it was not successfully resolved." },
{ ch:5, lo:"FL-5.5.2", q:"A defect is found during testing but the project manager decides it will not be fixed because the cost of fixing exceeds the business impact. The defect status is BEST set to:", opts:["a) Rejected","b) Deferred","c) Closed — Won't Fix","d) New"], ans:"c", rationale:"When a decision is made not to fix a defect (due to cost/benefit), it is closed with a won't fix resolution — not deferred (which implies future fix)." },
{ ch:5, lo:"FL-5.5.2", q:"What does the status 'Deferred' mean for a defect?", opts:["a) The defect has been fixed and verified","b) The defect has been decided not to fix at all","c) The fix will be addressed in a future release rather than the current one","d) The defect is waiting to be assigned to a developer"], ans:"c", rationale:"Deferred means the defect is acknowledged but will be fixed in a future iteration or release, not the current one." },
{ ch:5, lo:"FL-5.3.2", q:"Which of the following BEST describes what a test progress report communicates?", opts:["a) A complete list of all test cases in the test suite","b) Current status of testing against plan, including metrics, risks, and issues for stakeholders","c) A technical analysis of each defect found during the test cycle","d) Final quality assessment and recommendation for release"], ans:"b", rationale:"Test progress reports provide ongoing status updates: test execution progress, defect counts, coverage, and risks." },
{ ch:5, lo:"FL-5.3.2", q:"A test summary report indicates 95% of planned test cases executed, 5 open critical defects, and 92% pass rate. Which conclusion is MOST appropriate?", opts:["a) The system should be released immediately since 92% of tests pass","b) Stakeholders should be informed of the 5 open critical defects and a risk-based release decision should be made","c) The test team should immediately fix the 5 critical defects themselves","d) The summary shows testing is complete and no further action is needed"], ans:"b", rationale:"Open critical defects are a significant quality signal. The test summary informs stakeholders who make a risk-based go/no-go decision." },
{ ch:5, lo:"FL-5.2.2", q:"Risk-based testing reduces product risk by:", opts:["a) Eliminating all identified risks before testing begins","b) Increasing test coverage of high-risk areas to detect defects before they reach production","c) Transferring risk responsibility to the development team","d) Avoiding testing of low-risk areas entirely"], ans:"b", rationale:"Risk-based testing mitigates risk by applying more testing effort where failure likelihood and impact are highest." },
{ ch:5, lo:"FL-5.2.2", q:"A risk has been identified: 'The third-party payment gateway may not be available during peak load.' Which risk response is MOST appropriate for a testing team?", opts:["a) Accept the risk and do nothing","b) Test with a simulated payment gateway under load conditions to assess failure behavior","c) Remove all payment tests from the test plan","d) Transfer the risk to the payment gateway vendor only"], ans:"b", rationale:"Mitigating the risk through testing (simulating failure scenarios) gives the team data to address the risk before production." },
{ ch:5, lo:"FL-5.1.3", q:"Which estimation technique bases its estimate on the expert knowledge of people who have done similar work before?", opts:["a) Work breakdown structure","b) Expert-based estimation (e.g., Wideband Delphi)","c) Metrics-based estimation","d) PERT analysis"], ans:"b", rationale:"Expert-based estimation (including Wideband Delphi) uses expert judgment from experienced practitioners to estimate effort." },
{ ch:6, lo:"FL-6.1.1", q:"Which of the following is a 'test design and implementation' tool?", opts:["a) Jira (defect tracker)","b) TestRail (test management)","c) Cucumber (BDD/specification tool)","d) JMeter (load testing)"], ans:"c", rationale:"Cucumber is a BDD tool that supports writing executable specifications — a test design and implementation tool." },
{ ch:6, lo:"FL-6.1.1", q:"A team wants to ensure test results, test cases, and builds are always linked so they know exactly which tests passed against which version. Which tool category supports this?", opts:["a) Static analysis tools","b) Test management tools with traceability features","c) Performance testing tools","d) Code coverage tools"], ans:"b", rationale:"Test management tools with traceability link test cases to requirements, builds, and results — supporting configuration and impact tracking." },
{ ch:6, lo:"FL-6.1.1", q:"Which of the following tools would MOST directly help a team measure how much of their codebase is exercised by automated tests?", opts:["a) A defect tracking tool","b) A code coverage tool (e.g., JaCoCo, Istanbul)","c) A performance testing tool","d) A requirements management tool"], ans:"b", rationale:"Code coverage tools instrument code and report which statements, branches, or paths are exercised by tests." },
{ ch:6, lo:"FL-6.2.1", q:"A team has automated 80% of their regression tests. They find that after a major UI redesign, 60% of automated tests fail due to locator changes. This demonstrates which risk of test automation?", opts:["a) Automation always increases the number of defects found","b) High maintenance cost when the application changes significantly","c) Automated tests run slower than manual tests","d) Automation requires more testers than manual testing"], ans:"b", rationale:"UI changes break locators — a classic automation maintenance problem showing the high cost of maintaining automated test suites." },
{ ch:6, lo:"FL-6.2.1", q:"A team is evaluating whether to automate a set of tests that are executed only once per year for a major release. Which factor argues AGAINST automation?", opts:["a) The tests are complex","b) The return on investment is poor — automation effort exceeds the time saved given low execution frequency","c) The team lacks testing skills","d) The application is too new to automate"], ans:"b", rationale:"Automation ROI depends on frequency: tests run rarely save little time but still cost to build and maintain — low ROI argues against automation." },
{ ch:6, lo:"FL-6.2.1", q:"Which of the following is a PREREQUISITE for successful test automation introduction?", opts:["a) 100% manual test coverage must exist before automation begins","b) A stable, testable architecture with defined interfaces and reliable test environments","c) The entire development team must learn the automation tool","d) All tests must be converted to automated tests simultaneously"], ans:"b", rationale:"Automation requires stable interfaces (to avoid constant script breakage) and reliable environments (to produce consistent results)." },
{ ch:6, lo:"FL-6.2.1", q:"Which of the following BEST describes the concept of 'automating a bad test'?", opts:["a) Writing a test in a programming language the team does not know","b) Running an automated test on the wrong environment","c) Automating a poorly designed test case that does not effectively verify the intended behavior","d) Using an outdated automation framework"], ans:"c", rationale:"Automation amplifies both good and bad tests. A poorly designed test automated quickly still fails to provide meaningful coverage." },
{ ch:6, lo:"FL-6.1.1", q:"Which tool type would a team use to detect that a variable is declared but never used anywhere in the codebase?", opts:["a) Test execution tool","b) Static analysis tool","c) Performance testing tool","d) Test data generation tool"], ans:"b", rationale:"Static analysis tools scan code for issues (unused variables, null dereferences, code smells) without executing it." },
{ ch:6, lo:"FL-6.2.1", q:"Which of the following CORRECTLY states a benefit of test automation?", opts:["a) Automated tests always detect more defects than experienced human testers","b) Automated tests can execute many test cases quickly and repeatably, reducing regression testing time","c) Test automation eliminates the need to design test cases","d) Test automation guarantees 100% defect detection"], ans:"b", rationale:"The core benefit of automation is speed and repeatability — enabling frequent regression runs that would be prohibitive manually." },
];
    // =====================================================================
// BUILD DOCUMENT
// =====================================================================
const { Document, Packer, Paragraph, TextRun, HeadingLevel,
    AlignmentType, LevelFormat, Header, Footer, PageNumber,
    BorderStyle } = require('docx');
const fsm = require('fs');

const CHAP_TITLES = {
    1: "Chapter 1: Fundamentals of Testing",
    2: "Chapter 2: Testing Throughout the SDLC",
    3: "Chapter 3: Static Testing",
    4: "Chapter 4: Test Analysis and Design",
    5: "Chapter 5: Managing the Test Activities",
    6: "Chapter 6: Test Tools"
};

function makeChildren() {
    const children = [];

    // Title
    children.push(new Paragraph({
        heading: HeadingLevel.HEADING_1,
        alignment: AlignmentType.CENTER,
        children: [new TextRun({ text: "ISTQB CTFL v4.0 — 200 Practice Questions", bold: true, size: 36 })]
    }));
    children.push(new Paragraph({
        alignment: AlignmentType.CENTER,
        children: [new TextRun({ text: "All Syllabus Chapters | K1/K2/K3 Cognitive Levels | With Answers & Rationale", size: 22, italics: true })]
    }));
    children.push(new Paragraph({ children: [new TextRun("")] }));
    children.push(new Paragraph({
        children: [new TextRun({
            text: "Instructions: Each question carries 1 point. Pass mark is 65% (26/40 on real exam). Study the rationale for wrong answers as much as for correct ones.",
            size: 20
        })]
    }));
    children.push(new Paragraph({ children: [new TextRun("")] }));

    let currentCh = 0;
    questions.forEach((item, idx) => {
        const n = idx + 1;
        if (item.ch !== currentCh) {
            currentCh = item.ch;
            children.push(new Paragraph({
                heading: HeadingLevel.HEADING_2,
                children: [new TextRun({ text: CHAP_TITLES[currentCh], bold: true, size: 28 })]
            }));
        }

        // Question header
        children.push(new Paragraph({
            children: [
                new TextRun({ text: `Q${n}. `, bold: true, size: 22 }),
                new TextRun({ text: `[${item.lo}]  `, color: "0070C0", size: 20 }),
                new TextRun({ text: item.q, bold: true, size: 22 })
            ],
            spacing: { before: 200 }
        }));

        // Options
        item.opts.forEach(opt => {
            children.push(new Paragraph({
                children: [new TextRun({ text: `    ${opt}`, size: 20 })],
                spacing: { before: 40 }
            }));
        });

        // Answer
        const ansLabel = item.opts.find(o => o.startsWith(item.ans + ')')) || item.ans;
        children.push(new Paragraph({
            children: [
                new TextRun({ text: `Answer: ${item.ans.toUpperCase()})  `, bold: true, color: "375623", size: 20 }),
                new TextRun({ text: item.rationale, italics: true, color: "595959", size: 20 })
            ],
            spacing: { before: 60 },
            border: { bottom: { style: BorderStyle.SINGLE, size: 1, color: "CCCCCC", space: 4 } }
        }));
    });

    return children;
}

const doc = new Document({
    numbering: { config: [] },
    styles: {
        default: { document: { run: { font: "Arial", size: 22 } } },
        paragraphStyles: [
            {
                id: "Heading1", name: "Heading 1", basedOn: "Normal", next: "Normal", quickFormat: true,
                run: { size: 36, bold: true, font: "Arial", color: "1F3864" },
                paragraph: { spacing: { before: 400, after: 200 }, outlineLevel: 0 }
            },
            {
                id: "Heading2", name: "Heading 2", basedOn: "Normal", next: "Normal", quickFormat: true,
                run: { size: 28, bold: true, font: "Arial", color: "2E75B6" },
                paragraph: { spacing: { before: 300, after: 100 }, outlineLevel: 1 }
            },
        ]
    },
    sections: [{
        properties: {
            page: {
                size: { width: 12240, height: 15840 },
                margin: { top: 1080, right: 1080, bottom: 1080, left: 1080 }
            }
        },
        headers: {
            default: new Header({
                children: [new Paragraph({
                    alignment: AlignmentType.RIGHT,
                    children: [new TextRun({ text: "ISTQB CTFL v4.0 Practice Exam — 200 Questions", size: 16, color: "888888" })]
                })]
            })
        },
        footers: {
            default: new Footer({
                children: [new Paragraph({
                    alignment: AlignmentType.CENTER,
                    children: [
                        new TextRun({ text: "Page ", size: 18 }),
                        new PageNumber({ format: "decimal" })
                    ]
                })]
            })
        },
        children: makeChildren()
    }]
});

Packer.toBuffer(doc).then(buf => {
    fsm.writeFileSync('/mnt/user-data/outputs/ISTQB_CTFL_200_Practice_Questions.docx', buf);
    console.log('Done. Questions: ' + questions.length);
});